public class CustomerService { private final CustomerRepository repo; public CustomerService(CustomerRepository repo) { this.repo = repo; } public void addCustomer(Customer c) { repo.save(c); } public Customer getCustomer(String id) { return repo.findById(id); } public java.util.List<Customer> getAllCustomers() { return repo.findAll(); } public boolean removeCustomer(String id) { boolean ok = repo.delete(id); System.out.println("[Service] Delete " + id + ": " + ok); return ok; } }